import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const agentResponse = await client.agent.create({
    organization_id: "org_9f2k1",
    widget_settings_id: 12,
    name: "Support line",
    agent_name: "Ava",
    model: "gpt-4.1-mini",
    voice_id: "alloy",
    temperature: 0.4,
    enable_voicemail_detection: true,
    ivr_options: {
      "1": "sales",
      "2": "support"
    },
    selected_tools: {
      "crm_lookup": true
    },
    start_speaker: "agent"
  });

  console.log(agentResponse.id);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  await client.agent.delete("101", {
    organization_id: "org_9f2k1"
  });

  // Returns void on successful deletion

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const agent = await client.agent.get("101", {
    organization_id: "org_9f2k1"
  });

  console.log(agent.name);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const agents = await client.agent.list({
    organization_id: "org_9f2k1",
    offset: 0,
    limit: 20
  });

  console.log(agents.data);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const agentResponse = await client.agent.updateStatus("101", {
    organization_id: "org_9f2k1",
    status: "AGENT_STATUS_INACTIVE"
  });

  console.log(agentResponse.status);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const agentResponse = await client.agent.update("101", {
    organization_id: "org_9f2k1",
    name: "Support line - EN",
    temperature: 0.35,
    enable_voicemail_detection: true,
    analysis_summary_prompt: "Summarize blockers and follow-ups.",
    start_speaker: "agent"
  });

  console.log(agentResponse.updated_at);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const numberResponse = await client.phoneNumber.buy({
    phone_number: "+14155552671",
    price: 1.0,
    per_minute_price_inbound: 1,
    per_minute_price_outbound: 2
  });

  console.log(numberResponse.phone_number);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const config = await client.telephony.createProvider({
    type: "twilio",
    owner_type: "organization",
    friendly_name: "My Twilio Account",
    client_id: "ACXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX",
    client_secret: "your_auth_token_here"
  });

  console.log(config.id);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const importedNumber = await client.telephony.importNumber({
    phone: "+14155552671",
    type: "sip",
    name: "Main SIP Trunk",
    termination_uri: "sip:14155552671@sip.example.com",
    sip_username: "admin",
    sip_password: "secr3t"
  });

  console.log(importedNumber.status);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const availableNumbers = await client.telephony.listAvailableNumbers("US", {
    page_size: 10,
    region: "CA"
  });

  console.log(availableNumbers.data);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const numbers = await client.telephony.listPurchasedNumbers({
    iso_country: "US",
    is_active: true
  });

  console.log(numbers.data);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const numbers = await client.telephony.listTwilioNumbers();
  console.log(numbers.data);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const call = await client.telephony.releaseNumber("+14155552671");
  console.log(call.status);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const toolResponse = await client.tool.create({
    organization_id: "org_9f2k1",
    name: "crm_lookup",
    description: "Fetch customer profile from CRM",
    type: "http",
    definition: {
      url: "https://api.example.com/customers/{phone}",
      method: "GET"
    }
  });

  console.log(toolResponse.id);

curl -X POST "https://api.ravan.ai/api/v1/tools" \
    -H "Authorization: Bearer <token>" \
    -H "Content-Type: application/json" \
    -d '{
      "organization_id": "org_9f2k1",
      "name": "crm_lookup",
      "description": "Fetch customer profile from CRM",
      "type": "http",
      "definition": {
        "url": "https://api.example.com/customers/{phone}",
        "method": "GET"
      }
    }'

