  console.log(tools.data);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const toolResponse = await client.tool.update("21", {
    organization_id: "org_9f2k1",
    name: "crm_lookup",
    description: "Fetch and summarize customer profile",
    type: "http",
    definition: {
      "url": "https://api.example.com/customers/{phone}",
      "method": "GET",
      "timeout_ms": 2000
    }
  });

  console.log(toolResponse.name);

import Agni from 'agni-sdk';

  const client = new Agni({
    apiKey: 'YOUR_AGNI_API_KEY',
  });

  const widgetConfig = await client.widget.create({
    bot_name: "Ava",
    bot_auto_start: true,
    bot_position: "BOT_POSITION_BOTTOM_RIGHT",
    bot_logo: "https://cdn.ravan.ai/bot-logo.svg",
    custom_form_fields: {
      "company": {
        "type": "text",
        "required": true
      }
    },
    theme: {
      "primary": "#16A34A"
    },
    language: "en",
    consent_content: "By continuing, you agree to recording.",
    consent_title: "Consent"
  });

  console.log(widgetConfig.id);

